 47	void free_eNB_ulsch(LTE_eNB_ULSCH_t *ulsch)
 48	{
 49	  if (ulsch) {
 50	    for (int i = 0; i < 8; i++) {
 51	      if (ulsch->harq_processes[i]) {
 52	        if (ulsch->harq_processes[i]->decodedBytes) {
 53	          free16(ulsch->harq_processes[i]->decodedBytes,MAX_ULSCH_PAYLOAD_BYTES);
 54	          ulsch->harq_processes[i]->decodedBytes = NULL;
 55	        }
 56	
 57	        for (int r = 0; r < MAX_NUM_ULSCH_SEGMENTS; r++) {
 58	          free16(ulsch->harq_processes[i]->c[r],((r==0)?8:0) + 768);
 59	          ulsch->harq_processes[i]->c[r] = NULL;
 60	        }
 61	
 62	        for (int r = 0; r < MAX_NUM_ULSCH_SEGMENTS; r++)
 63	          if (ulsch->harq_processes[i]->d[r]) {
 64	            free16(ulsch->harq_processes[i]->d[r],((3*8*6144)+12+96)*sizeof(short));
 65	            ulsch->harq_processes[i]->d[r] = NULL;
 66	          }
 67	
 68	        free16(ulsch->harq_processes[i],sizeof(LTE_UL_eNB_HARQ_t));
 69	        ulsch->harq_processes[i] = NULL;
 70	      }
 71	    }
 72	
 73	    free16(ulsch,sizeof(LTE_eNB_ULSCH_t));
 74	  }
 75	}
