 77	LTE_eNB_ULSCH_t *new_eNB_ulsch(uint8_t max_turbo_iterations,uint8_t N_RB_UL, uint8_t abstraction_flag) {
 78	  LTE_eNB_ULSCH_t *ulsch;
 79	  uint8_t exit_flag = 0,i,r;
 80	  unsigned char bw_scaling =1;
 81	
 82	  switch (N_RB_UL) {
 83	    case 6:
 84	      bw_scaling =16;
 85	      break;
 86	
 87	    case 25:
 88	      bw_scaling =4;
 89	      break;
 90	
 91	    case 50:
 92	      bw_scaling =2;
 93	      break;
 94	
 95	    default:
 96	      bw_scaling =1;
 97	      break;
 98	  }
 99	
100	  ulsch = (LTE_eNB_ULSCH_t *)malloc16(sizeof(LTE_eNB_ULSCH_t));
101	
102	  if (ulsch) {
103	    memset(ulsch,0,sizeof(LTE_eNB_ULSCH_t));
104	    ulsch->max_turbo_iterations = max_turbo_iterations;
105	    ulsch->Mlimit = 4;
106	
107	    for (i=0; i<8; i++) {
108	      //      printf("new_ue_ulsch: Harq process %d\n",i);
109	      ulsch->harq_processes[i] = (LTE_UL_eNB_HARQ_t *)malloc16(sizeof(LTE_UL_eNB_HARQ_t));
110	
111	      if (ulsch->harq_processes[i]) {
112	        memset(ulsch->harq_processes[i],0,sizeof(LTE_UL_eNB_HARQ_t));
113	        init_abort(&ulsch->harq_processes[i]->abort_decode);
114	        ulsch->harq_processes[i]->decodedBytes = (uint8_t *)malloc16(MAX_ULSCH_PAYLOAD_BYTES/bw_scaling);
115	
116	        if (ulsch->harq_processes[i]->decodedBytes)
117	          memset(ulsch->harq_processes[i]->decodedBytes,0,MAX_ULSCH_PAYLOAD_BYTES/bw_scaling);
118	        else
119	          exit_flag=3;
120	
121	        if (abstraction_flag==0) {
122	          for (r=0; r<MAX_NUM_ULSCH_SEGMENTS/bw_scaling; r++) {
123	            ulsch->harq_processes[i]->c[r] = (uint8_t *)malloc16(((r==0)?8:0) + 3+768);
124	
125	            if (ulsch->harq_processes[i]->c[r])
126	              memset(ulsch->harq_processes[i]->c[r],0,((r==0)?8:0) + 3+768);
127	            else
128	              exit_flag=2;
129	
130	            ulsch->harq_processes[i]->d[r] = (short *)malloc16(((3*8*6144)+12+96)*sizeof(short));
131	
132	            if (ulsch->harq_processes[i]->d[r])
133	              memset(ulsch->harq_processes[i]->d[r],0,((3*8*6144)+12+96)*sizeof(short));
134	            else
135	              exit_flag=2;
136	          }
137	        }
138	      } else {
139	        exit_flag=1;
140	      }
141	    }
142	
143	    if (exit_flag==0)
144	      return(ulsch);
145	  }
146	
147	  LOG_E(PHY,"new_ue_ulsch: exit_flag = %d\n",exit_flag);
148	  free_eNB_ulsch(ulsch);
149	  return(NULL);
150	}
